import React from "react"
import Select from 'react-select'
//import Calendar from 'react-select-date'
import { Calendar, DateObject } from "react-multi-date-picker"
import { properties } from '../../properties/properties.js'
import Moment from 'moment'
import {Tab, Tabs, TabList, TabPanel} from 'react-tabs'
import 'react-tabs/style/react-tabs.css'
import FullCalendar from '@fullcalendar/react' // must go before plugins
import interactionPlugin from "@fullcalendar/interaction" // needed for dayClick
import timeGridPlugin from '@fullcalendar/timegrid'



class RoomAdmin extends React.Component {

    constructor(props) {
        super(props);
        this.state = {
            screen: 0, roomResults: [], reservationResults: [], addRoom: false, roomName: "", employeeRoomCheckbox: false,
            roomEmployeeID: "", roomEmployeeName: "", editRoom: false, editRoomID: 0, bookedSpaceEvents: []
        };
    }

    handleCancelReservation = (event) => {


        if (window.confirm('Are you sure to cancel ' + event.title + " (" + Moment(event.start).format("MM-DD-YYYY") + " " + Moment(event.start).format("hh:mm A") + " - " + Moment(event.end).format("hh:mm A") + ")?")) {
            //this.setState({screen: 0})

            let headers = new Headers();

            headers.append('Content-Type', 'application/json');
            headers.append('Accept', 'application/json');

            fetch(properties.backend + `deleteScheduleadmin?id=` + event.id, {
                "method": "GET",
                headers: headers
              })
              .then(response => response.json())
              .then(response => {
                var bookedSpaceEvents = []



                response.filter(rec => Moment(rec.end_date_time) >= Moment()).map(reservRec => {
                    bookedSpaceEvents.push({employeeID: reservRec.cyber_user.split("::")[0], employeeName: reservRec.cyber_user.split("::")[1], title: reservRec.room_name, id: reservRec.id, start: reservRec.start_date_time, end: reservRec.end_date_time, comment: reservRec.comment})
                })


                bookedSpaceEvents.sort(function(a,b) {
                    var x = Moment(a.start)
                    var y = Moment(b.start)
                    return x < y ? -1 : x > y ? 1: 0;
                })


                this.setState({bookedSpaceEvents: bookedSpaceEvents})

              })
              .catch(err => {
                console.log(err);
              });

        }


    }


    handleAddEditRoomSubmit = () => {


        this.setState({screen: 0});

        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');


        var roomRequest = {room_name: this.state.roomName, employeeID: this.state.roomEmployeeID, employeeName: this.state.roomEmployeeName}

        var backUrl = properties.backend + `addroom`

        if (this.state.editRoom) {
            roomRequest.id = this.state.editRoomID
            backUrl = properties.backend + `editroom`
        }

        fetch(backUrl, {
          "method": "POST",
          headers: headers,
          body: JSON.stringify(roomRequest)

        })
        .then(response => response.json())
        .then(response => {
            this.setState({roomResults: response})
            this.setState({screen: 1})
            this.handleCancelAddEditRoom()
        })
        .catch(err => {
          console.log(err);
        });
    }


    handleCancelAddEditRoom = () => {
        this.setState({addRoom: false})
        this.setState({editRoom: false})
        this.handleCancelRoom()
    }

    handleCancelRoom = () => {
        this.setState({roomName: ""})
        this.setState({employeeRoomCheckbox: false})
        this.setState({roomEmployeeID: ""})
        this.setState({roomEmployeeName: ""})
        this.setState({editRoomID: 0})
    }


    updateEmployeeID = (event) => {
        this.setState({roomEmployeeID: event.target.value})
    }

    updateEmployeeName = (event) => {
        this.setState({roomEmployeeName: event.target.value})
    }

    updateRoomName = (event) => {
        this.setState({roomName: event.target.value})
    }

    handleEmployeeRoomChange = (event) => {
        this.setState({employeeRoomCheckbox: event.target.checked})
        if (!event.target.checked) {
            this.setState({roomEmployeeID: ""})
            this.setState({roomEmployeeName: ""})
        }
    }

    handleDeleteRoom = (item) => {
        if (window.confirm('Are you sure you wish to delete ' + item.room_name)) {
            this.setState({screen: 0})

            let headers = new Headers();

            headers.append('Content-Type', 'application/json');
            headers.append('Accept', 'application/json');

            fetch(properties.backend + `deleteRoom?id=` + item.id, {
                "method": "GET",
                headers: headers
              })
              .then(response => response.json())
              .then(response => {
                //console.log(response);
                this.setState({roomResults: response})
                this.setState({screen: 1})
                this.handleCancelAddEditRoom()
                //this.setState({addRoom: false})
                //_forEach(response, d => console.log(d.name))
                //console.log(this.state.results)
              })
              .catch(err => {
                console.log(err);
              });

        }
    }

    handleEditRoom = (editItem) => {
        this.setState({editRoom: true})
        this.setState({addRoom: false})
        this.handleCancelRoom()
        this.setState({roomName: editItem.room_name})
        this.setState({employeeRoomCheckbox: false})
        this.setState({roomEmployeeID: ""})
        if (editItem.owner != null && editItem.owner.length > 0) {
            this.setState({employeeRoomCheckbox: true})
            this.setState({roomEmployeeID: editItem.owner.split("::")[0]})
            this.setState({roomEmployeeName: editItem.owner.split("::")[1]})
        }
        this.setState({editRoomID: editItem.id})
    }  

    handleAddRoom = () => {
        this.setState({addRoom: true})
        this.setState({editRoom: false})
        this.handleCancelRoom()
    }


    componentDidMount() {

        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');

        fetch(properties.backend + `getavailableroom`, {
            "method": "GET",
            headers: headers
          })
          .then(response => response.json())
          .then(response => {
            //console.log(response);
            this.setState({roomResults: response})
            this.setState({addRoom: false})
            //this.setState({screen: 1})
            //_forEach(response, d => console.log(d.name))
            //console.log(this.state.results)

            fetch(properties.backend + `getreservation?all=1`, {
                "method": "GET",
                headers: headers
              })
              .then(response => response.json())
              .then(response => {
                //console.log(response);
                this.setState({reservationResults: response})
                this.setState({screen: 1})
                //_forEach(response, d => console.log(d.name))
                //console.log(this.state.results)

                var bookedSpaceEvents = []



                response.filter(rec => Moment(rec.end_date_time) >= Moment()).map(reservRec => {
                    bookedSpaceEvents.push({employeeID: reservRec.cyber_user.split("::")[0], employeeName: reservRec.cyber_user.split("::")[1], title: reservRec.room_name, id: reservRec.id, start: reservRec.start_date_time, end: reservRec.end_date_time, comment: reservRec.comment})
                })


                bookedSpaceEvents.sort(function(a,b) {
                    var x = Moment(a.start)
                    var y = Moment(b.start)
                    return x < y ? -1 : x > y ? 1: 0;
                })


                this.setState({bookedSpaceEvents: bookedSpaceEvents})



              })
              .catch(err => {
                console.log(err);
              });



          })
          .catch(err => {
            console.log(err);
          });





    }


    render() {


        var header = "Loading ..."
        var content = []
        var rightContent = []
        var leftContent = []


        if (this.state.screen === 1) {
            var tabContent = []
            //leftContent.push(<div>left</div>)
            //rightContent.push(<div>right</div>)

            var roomResults = this.state.roomResults

            //for (var index in roomResults) {
            roomResults.map(roomResult => {
                //var roomResult = roomResults[index]
                var leftContent2 = []
                var rightContent2 = []
                leftContent2.push(<div style={{marginBottom: "5px"}}>Room: {roomResult.room_name}</div>)
                if (roomResult.owner != null && roomResult.owner.length > 0) {
                    var employeeInfo = roomResult.owner.split("::")
                    leftContent2.push(<div style={{marginBottom: "5px"}}>Employee Name: {employeeInfo[1]}</div>)
                    leftContent2.push(<div style={{marginBottom: "5px"}}>Employee ID: {employeeInfo[0]}</div>)

                }
                rightContent2.push(<div><button onClick={() => this.handleEditRoom(roomResult)}  id={"editRoom" + roomResult.id} style={{height: "25px", width: "60px", fontSize: "14px", backgroundColor: "lightgrey" }}>Edit</button>&nbsp;&nbsp;<button onClick={() => this.handleDeleteRoom(roomResult)} id={"deleteRoom" + roomResult.id}  style={{height: "25px", width: "60px", fontSize: "14px", backgroundColor: "lightgrey" }}>Delete</button></div>)
                leftContent.push(<div style={{display: "flex"}}><div style={{marginRight: "20px", width: "600px"}}>{leftContent2}</div><div style={{flex: "100%"}}>{rightContent2}</div></div>)
                leftContent.push(<div style={{marginBottom: "5px"}}><hr></hr></div>)
            })


            if (this.state.addRoom || this.state.editRoom) {
                var tempContent = []

                if (this.state.addRoom) {
                    tempContent.push(<div>Add Room<hr></hr></div>)
                }

                if (this.state.editRoom) {
                    tempContent.push(<div>Edit Room<hr></hr></div>)
                }

                tempContent.push(<div style={{marginBottom:"10px"}}>Room Name: <input type="text" onChange={event => this.updateRoomName(event)} value={this.state.roomName}></input></div>)
                tempContent.push(<div style={{marginBottom:"10px"}}>Employee Room: <input type="checkbox" onChange={event => this.handleEmployeeRoomChange(event)} checked={this.state.employeeRoomCheckbox}></input></div>)

                if (this.state.employeeRoomCheckbox) {
                    tempContent.push(<div style={{marginBottom:"10px"}}>Employee ID: <input type="text" onChange={event => this.updateEmployeeID(event)} value={this.state.roomEmployeeID}></input></div>)
                    tempContent.push(<div style={{marginBottom:"10px"}}>Employee Name: <input type="text" onChange={event => this.updateEmployeeName(event)} value={this.state.roomEmployeeName}></input></div>)
                }


                tempContent.push(<div style={{marginTop: "15px"}}><button onClick={() => this.handleCancelAddEditRoom()}  id="cancelBooking" style={{height: "30px", width: "120px", fontSize: "16px", backgroundColor: "yellow" }}>Cancel</button>&nbsp;&nbsp;<button onClick={() => this.handleAddEditRoomSubmit()}  id="addRoom" style={{height: "30px", width: "120px", fontSize: "16px", backgroundColor: "green" }}>Confirm</button></div>)


                rightContent.push(<div style={{marginTop: "20px", marginBottom: "20px", borderStyle:"solid",borderColor:"coral",padding:"10px"}}>{tempContent}</div>)
            }


            var yourSpace = []
            if (this.state.bookedSpaceEvents.length > 0) {

              this.state.bookedSpaceEvents.map(event => {
                  yourSpace.push(<div>Date: {Moment(event.start).format("MM/DD/YYYY")}&nbsp;&nbsp;<button onClick={() => this.handleCancelReservation(event)}  id="deleteReservation" style={{height: "25px", width: "200px", fontSize: "14px", backgroundColor: "yellow" }}>Cancel Reservation</button><hr></hr></div>)

                  yourSpace.push(<div style={{marginBottom: "5px"}}>{event.title}</div>)
                  yourSpace.push(<div style={{marginBottom: "5px"}}>Time: {Moment(event.start).format("hh:mm A")} - {Moment(event.end).format("hh:mm A")}</div>)

                  yourSpace.push(<div style={{marginBottom: "5px"}}>Employee ID: {event.employeeID}</div>)
                  yourSpace.push(<div style={{marginBottom: "5px"}}>Employee Name: {event.employeeName}</div>)



                  yourSpace.push(<div style={{marginBottom: "50px"}}>Note: {event.comment}</div>)
              })


            } else {
              yourSpace.push(<div style={{marginBottom: "5px"}}>You don't have any reservation.</div>)
            }




            tabContent.push(<Tabs>
                <TabList>
                    <Tab>Manage Rooms</Tab>
                    <Tab>Manage Reservation</Tab>
                </TabList>
                <TabPanel>
                    <h2><button onClick={() => this.handleAddRoom()}  id="addRoom" style={{height: "30px", width: "120px", fontSize: "16px", backgroundColor: "yellow" }}> + Add Room</button></h2>
                    <div></div>
                    <div style={{display: "flex"}}><div style={{marginRight: "50px"}}>{leftContent}</div><div style={{flex: "100%"}}>{rightContent}</div></div>
                </TabPanel>
                <TabPanel>
                    <h2>Manage Reservation</h2>
                    <div>{yourSpace}</div>
                </TabPanel>
            </Tabs>)

            content.push(tabContent)
            header = ""
        }

        return (
            <div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}
            </div>
        );


      }





}


export default RoomAdmin
